                if (!"http".equalsIgnoreCase(scheme) && !"https".equalsIgnoreCase(scheme)) {
                    return false;
                }

                // Additional security: Could add domain whitelist here if needed
                // Example: if (!uri.getHost().endsWith(".example.com")) return false;
            }

            // Reject URLs with potentially dangerous characters or patterns
            if (url.contains("\r") || url.contains("\n") || url.contains("\0")) {
                return false;
            }

            // Reject JavaScript URLs
            if (url.toLowerCase().startsWith("javascript:")) {
                return false;
            }

            // Reject data URLs
            if (url.toLowerCase().startsWith("data:")) {
                return false;
            }

            return true;

        } catch (URISyntaxException e) {
            // Invalid URL format
            return false;
        }
    }
}
